INSERT INTO `tours_tour` (`id`, `name`, `description`, `image`, `category`, `rating`, `reviews_count`, `price_per_seat`, `duration`, `location`, `is_active`, `created_at`) VALUES (1, 'Wah Gardens Tour', 'A historic Mughal garden featuring beautiful stone water channels, brick pavilions, and lush green trees.', 'images/wah_gardens.png', 'Parks', '4.60', 128, '1000.00', '1 Day', 'Wah Cantt, Punjab', 1, '2026-05-26 06:24:30.314474');
INSERT INTO `tours_tour` (`id`, `name`, `description`, `image`, `category`, `rating`, `reviews_count`, `price_per_seat`, `duration`, `location`, `is_active`, `created_at`) VALUES (2, 'Sher Shah Park Tour', 'A scenic family public park featuring green lawns, flower beds, and walking pathways.', 'images/sher_shah_park.png', 'Parks', '4.50', 98, '800.00', '1 Day', 'Wah Cantt, Punjab', 1, '2026-05-26 06:24:30.321589');
INSERT INTO `tours_tour` (`id`, `name`, `description`, `image`, `category`, `rating`, `reviews_count`, `price_per_seat`, `duration`, `location`, `is_active`, `created_at`) VALUES (3, 'Taxila Museum Tour', 'A world-famous museum hosting ancient Buddhist and Gandhara civilization sculptures and relics.', 'images/taxila_museum.png', 'Museums', '4.70', 156, '1200.00', '1 Day', 'Taxila, Punjab', 1, '2026-05-26 06:24:30.325198');
INSERT INTO `tours_tour` (`id`, `name`, `description`, `image`, `category`, `rating`, `reviews_count`, `price_per_seat`, `duration`, `location`, `is_active`, `created_at`) VALUES (4, 'Khanpur Dam Adventure', 'A beautiful turquoise blue water reservoir offering boating, jet skiing, parasailing, and swimming.', 'images/khanpur_dam.png', 'Lakes', '4.80', 210, '2500.00', '1 Day', 'Haripur, KPK', 1, '2026-05-26 06:24:30.328768');
INSERT INTO `tours_tour` (`id`, `name`, `description`, `image`, `category`, `rating`, `reviews_count`, `price_per_seat`, `duration`, `location`, `is_active`, `created_at`) VALUES (5, 'Mall of Wah Shopping', 'A modern commercial shopping mall featuring local brand stores, dining, and family entertainment.', 'images/mall_of_wah.png', 'Markets', '4.30', 75, '500.00', '1 Day', 'Wah Cantt, Punjab', 1, '2026-05-26 06:24:30.332098');

